using System.Collections;
using UnityEngine;

/// <summary>Cura o player em "amount" corações (PlayerProgress.Heal — já faz Clamp a maxHearts).</summary>
[System.Serializable]
public class Action_Heal : NpcAction
{
    [Tooltip("Quantidade de corações a curar.")]
    public int amount = 1;

    public override IEnumerator Execute(NpcController npc)
    {
        PlayerProgress.Instance?.Heal(amount);
        yield break;
    }
}

/// <summary>Causa dano ao player em "amount" corações (PlayerProgress.Damage — já faz Clamp a 0).</summary>
[System.Serializable]
public class Action_Damage : NpcAction
{
    [Tooltip("Quantidade de corações de dano.")]
    public int amount = 1;

    public override IEnumerator Execute(NpcController npc)
    {
        PlayerProgress.Instance?.Damage(amount);
        yield break;
    }
}

/// <summary>
/// Teleporta o player para a posição de "destination" (ex: um ponto de
/// cutscene, a entrada de uma sala, depois de um boss). Usa
/// Rigidbody2D.position quando disponível, para evitar problemas de
/// interpolação física.
/// </summary>
[System.Serializable]
public class Action_TeleportPlayer : NpcAction
{
    [Tooltip("Posição de destino. Vazio = não faz nada.")]
    public Transform destination;

    [Tooltip("Zera a velocidade do player após o teleporte (recomendado, evita herdar momentum antigo, ex: queda).")]
    public bool zeroVelocity = true;

    public override IEnumerator Execute(NpcController npc)
    {
        if (destination == null || npc.Player == null) yield break;

        var rb = npc.Player.GetComponent<Rigidbody2D>();
        if (rb != null)
        {
            rb.position = destination.position;
            if (zeroVelocity) rb.linearVelocity = Vector2.zero;
        }
        else
        {
            npc.Player.position = destination.position;
        }

        yield break;
    }
}

/// <summary>
/// Empurra o player com um impulso de velocidade (knockback) — útil para
/// explosões, armadilhas, ou um "soco" de um NPC hostil.
/// </summary>
[System.Serializable]
public class Action_PushPlayer : NpcAction
{
    [Tooltip("Velocidade aplicada ao player (X, Y).")]
    public Vector2 force = new Vector2(6f, 4f);

    [Tooltip("Se activo, o sinal do eixo X é calculado para empurrar o player para longe deste NPC (usa o valor absoluto de force.x). Se desactivo, usa force.x tal como está (direção fixa).")]
    public bool awayFromNpc = true;

    public override IEnumerator Execute(NpcController npc)
    {
        var player = npc.Player;
        if (player == null) yield break;

        var rb = player.GetComponent<Rigidbody2D>();
        if (rb == null) yield break;

        float forceX = force.x;

        if (awayFromNpc)
        {
            float sign = Mathf.Sign(player.position.x - npc.transform.position.x);
            if (sign == 0f) sign = 1f;
            forceX = sign * Mathf.Abs(force.x);
        }

        rb.linearVelocity = new Vector2(forceX, force.y);
        yield break;
    }
}

/// <summary>
/// Bloqueia ou desbloqueia o movimento do player (PlayerMotor2D.SetMovementLocked)
/// — útil para imobilizar o player durante uma cutscene de diálogo ou
/// enquanto o NPC está a falar/agir sobre ele.
/// </summary>
[System.Serializable]
public class Action_SetPlayerMovementLocked : NpcAction
{
    [Tooltip("true = bloqueia o movimento horizontal/salto do player. false = devolve o controlo.")]
    public bool locked = true;

    [Tooltip("Ao bloquear (locked = true), interrompe também qualquer habilidade 'com estado' activa (escalar, dash, balanço, língua, escudo, carregar objecto, ...) — item 8 da auditoria. Evita o player ficar a escalar/balançar durante o diálogo/cutscene.")]
    public bool cancelAbilities = true;

    [Tooltip("Motivo do cancelamento, passado a IAbility.Cancel — apenas informativo para as habilidades.")]
    public AbilityCancelReason cancelReason = AbilityCancelReason.Dialogue;

    public override IEnumerator Execute(NpcController npc)
    {
        var player = npc.Player;
        if (player == null) yield break;

        var motor = player.GetComponent<PlayerMotor2D>();
        // "npc" (não "this") é o source: o mesmo NPC normalmente bloqueia no
        // início do diálogo/cutscene e desbloqueia no fim através de Actions
        // diferentes — usar a mesma chave garante que o desbloqueio cancela
        // o bloqueio correspondente (ver PlayerMotor2D.SetMovementLocked).
        if (motor != null) motor.SetMovementLocked(locked, npc);

        if (locked && cancelAbilities)
        {
            var abilityRouter = player.GetComponent<AbilityRouter>();
            abilityRouter?.CancelAll(cancelReason);
        }

        yield break;
    }
}
